// Process collected files and folders
const files = $node["Collect Files"].json;
const folders = $node["Trigger"].json.folders || [];
const filesToPush = [];
const validFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'pdf', 'jpg', 'jpeg', 'png', 'webp', 'csv', 'json'];

if (Array.isArray(files)) {
  files.forEach(file => {
    const ext = file.split('.').pop().toLowerCase();
    if (validFileTypes.includes(ext)) {
      filesToPush.push(file);
    }
  });
}

return { filesToPush, folderCount: folders.length };

// Check if authentication token exists
const token = $node["Trigger"].json.khojToken || '';
const hostURL = $node["Trigger"].json.hostURL || 'https://app.khoj.dev';

if (!token || !hostURL) {
  throw new Error('Missing authentication token or host URL');
}

return { token, hostURL };

// Determine MIME type based on file extension
function filenameToMimeType(filename) {
  const ext = filename.split('.').pop().toLowerCase();
  const mimeTypes = {
    'pdf': 'application/pdf',
    'png': 'image/png',
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'webp': 'image/webp',
    'md': 'text/markdown',
    'markdown': 'text/markdown',
    'org': 'text/org',
    'txt': 'text/plain',
    'html': 'text/html',
    'xml': 'text/xml',
    'csv': 'text/csv',
    'json': 'application/json'
  };
  return mimeTypes[ext] || 'text/plain';
}

const files = $node["Filter Valid Files"].json.filesToPush || [];
const fileMetadata = files.map(file => ({
  path: file,
  mimeType: filenameToMimeType(file)
}));

return { fileMetadata };

// Handle sync response
const response = $node["Sync Files to Khoj"].json;
const statusCode = $node["Sync Files to Khoj"].executionStatus;

if (statusCode === 'success' || (response && response.status === 200)) {
  return {
    syncStatus: 'success',
    message: 'Files synced successfully',
    timestamp: new Date().toISOString()
  };
} else if (statusCode === 'error') {
  return {
    syncStatus: 'error',
    message: response.message || 'Sync failed',
    timestamp: new Date().toISOString()
  };
} else {
  return {
    syncStatus: 'unknown',
    message: 'Unknown sync status',
    timestamp: new Date().toISOString()
  };
}

// Update last sync timestamp on success
const syncResult = $node["Process Sync Result"].json;
const files = $node["Filter Valid Files"].json.filesToPush || [];

if (syncResult.syncStatus === 'success') {
  const lastSync = files.map(file => ({
    path: file,
    datetime: new Date().toISOString()
  }));
  return { lastSync, completed: true };
} else {
  return { lastSync: [], completed: false, error: syncResult.message };
}
